#nullable enable // autogenerated

using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2Logic.Entities;
using PVZEngine.Definitions;
using PVZEngine.Entities;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaEntityBehaviourNames.ignitable_Evoke)]
    public class IgnitableBehaviour_Evoke : ContraptionEvokeBehaviour
    {
        public IgnitableBehaviour_Evoke(string nsp, string name) : base(nsp, name)
        {
        }
        public override void Evoke(Entity entity)
        {
            base.Evoke(entity);
            entity.SetEvoked(true);
            IgnitableBehaviour.Ignite(entity);
        }
    }
}
